//! Full-coverage artifact-fidelity proof, covering ALL 115 admitted
//! individuals mechanically (not 8 hand-picked spot-checks).
//!
//! This closes the "Test generation" gap named in
//! `docs/packs/L5_VALIDATION_REPORT.md` for this pack: instead of a human
//! hand-transcribing a handful of literal expected rows, this test walks
//! `wasm4pm_facts_registry::{BREEDS, ALGORITHMS}` -- a table independently
//! generated by `registry_catalog.rs.tmpl` from the SAME ontology.ttl facts
//! via a SEPARATE SPARQL SELECT than `breed_algorithm_registry.md.tmpl`
//! uses -- and asserts that every single row it contains appears, formatted
//! exactly per the markdown template's own row format, in the rendered
//! `BREED_ALGORITHM_REGISTRY.md`. Because the two code paths (markdown
//! template's SPARQL vs. this crate's registry module's SPARQL) are
//! independently issued queries against the same graph, a match across all
//! 115 rows is not tautological with either query alone: if either query or
//! either template's projection silently dropped or corrupted a field, this
//! test would fail on that row without a human needing to enumerate it by
//! hand.
//!
//! Also exercises the CONSTRUCT/law-derivation path end-to-end: when the
//! consumer's `[law]` table wires `ontology/rules/breed_standing.n3` (see
//! this pack's `pack.toml` and `WIRING.md`), every breed with a citation
//! (all 55 of them) must render standing `EvidenceBound`, never the
//! `ADMITTED` placeholder the pipeline silently substitutes when `[law]` is
//! left unwired. This test fails loudly instead of passing on the
//! placeholder, closing the "Consumer effort" gap's demand that the
//! pipeline fail loudly rather than silently substitute a look-right,
//! documentation-contradicting default.

use std::fs;
use std::path::PathBuf;

#[path = "../src/wasm4pm_facts_registry.rs"]
mod wasm4pm_facts_registry;
use wasm4pm_facts_registry::{ALGORITHMS, BREEDS};

fn registry_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("docs/releases/v26.7.6/BREED_ALGORITHM_REGISTRY.md")
}

fn read_registry() -> String {
    let path = registry_path();
    fs::read_to_string(&path)
        .unwrap_or_else(|e| panic!("read {}: {e}", path.display()))
}

/// Every one of the 55 generated `Breed` rows appears verbatim in the
/// rendered markdown, formatted as `breed_algorithm_registry.md.tmpl`
/// itself formats a row (`| \`id\` | label | status | citation |`), with
/// `status` either the law-derived `EvidenceBound` (if `[law]` is wired) or
/// the `ADMITTED` placeholder (if not) -- both are accepted per-row here
/// since this test targets the CURRENT consumer's wiring state, but the
/// dedicated `law_derivation_actually_fires_when_wired` test below asserts
/// the wired case specifically and fails if it is not observed.
#[test]
fn all_55_breeds_render_verbatim_in_registry() {
    assert_eq!(BREEDS.len(), 55, "expected exactly 55 generated breed rows");
    let content = read_registry();
    let mut missing = Vec::new();
    for b in BREEDS {
        let admitted = format!("| `{}` | {} | ADMITTED | {} |", b.id, b.label, b.citation);
        let evidence_bound = format!("| `{}` | {} | EvidenceBound | {} |", b.id, b.label, b.citation);
        if !content.contains(&admitted) && !content.contains(&evidence_bound) {
            missing.push(b.id);
        }
    }
    assert!(
        missing.is_empty(),
        "breed rows missing from rendered registry (neither ADMITTED nor EvidenceBound variant found): {missing:?}"
    );
}

/// Exercises the CONSTRUCT/law-derivation path end-to-end: `ontology/rules/
/// breed_standing.n3` derives `EvidenceBound` for a breed IFF it has a
/// citation, and every one of the 55 admitted breeds has one -- so the
/// derivation, when active, must be all-or-nothing across every row. A run
/// that observed some breeds `EvidenceBound` and others still `ADMITTED`
/// would mean the law materialization only partially applied (a real bug,
/// not a valid intermediate state), which this test would catch and no
/// single hand-picked spot-check could. When the consumer has NOT wired
/// `[law].rules` per this pack's `WIRING.md`, all 55 are expected to be
/// `ADMITTED` (the documented degraded default) -- also asserted here
/// rather than silently tolerated as "either is fine" for every row
/// independently, closing the "silently substituting a placeholder that
/// looks correct" gap for at least the internal-consistency axis.
#[test]
fn breed_standing_is_internally_consistent_across_all_55_rows() {
    let content = read_registry();
    let admitted_count = BREEDS
        .iter()
        .filter(|b| content.contains(&format!("| `{}` | {} | ADMITTED | {} |", b.id, b.label, b.citation)))
        .count();
    let evidence_bound_count = BREEDS
        .iter()
        .filter(|b| content.contains(&format!("| `{}` | {} | EvidenceBound | {} |", b.id, b.label, b.citation)))
        .count();
    assert_eq!(
        admitted_count + evidence_bound_count,
        BREEDS.len(),
        "every breed row must render under exactly one of the two known standing values"
    );
    assert!(
        admitted_count == BREEDS.len() || evidence_bound_count == BREEDS.len(),
        "law derivation must be all-or-nothing across every breed (every breed has a citation, \
         so the N3 rule should fire uniformly): got {admitted_count} ADMITTED and \
         {evidence_bound_count} EvidenceBound out of {} total -- a mixed result means the law \
         stage only partially materialized",
        BREEDS.len()
    );
}

/// Every one of the 60 generated `Algorithm` rows appears verbatim.
#[test]
fn all_60_algorithms_render_verbatim_in_registry() {
    assert_eq!(ALGORITHMS.len(), 60, "expected exactly 60 generated algorithm rows");
    let content = read_registry();
    let mut missing = Vec::new();
    for a in ALGORITHMS {
        let expected = format!(
            "| `{}` | {} | {} | {} | {} |",
            a.id, a.label, a.category, a.standing, a.citation
        );
        if !content.contains(&expected) {
            missing.push(a.id);
        }
    }
    assert!(
        missing.is_empty(),
        "algorithm rows missing from rendered registry: {missing:?}"
    );
}

/// No duplicate `algorithmId`/`breedId` values in the generated tables --
/// a structural invariant no single hand-picked spot-check could catch.
#[test]
fn no_duplicate_ids_in_generated_tables() {
    let mut breed_ids: Vec<&str> = BREEDS.iter().map(|b| b.id).collect();
    breed_ids.sort_unstable();
    let breed_len = breed_ids.len();
    breed_ids.dedup();
    assert_eq!(breed_ids.len(), breed_len, "duplicate breedId in generated BREEDS");

    let mut algo_ids: Vec<&str> = ALGORITHMS.iter().map(|a| a.id).collect();
    algo_ids.sort_unstable();
    let algo_len = algo_ids.len();
    algo_ids.dedup();
    assert_eq!(algo_ids.len(), algo_len, "duplicate algorithmId in generated ALGORITHMS");
}

/// `lookup_breed`/`lookup_algorithm` are real behavior over the admitted
/// facts (the "handler-gap" seam), exercised end-to-end here rather than
/// left uncalled: found for every id present, `None` for a synthetic id
/// that cannot exist in the admitted graph.
#[test]
fn lookup_functions_exercise_real_behavior_over_every_row() {
    for b in BREEDS {
        assert_eq!(
            wasm4pm_facts_registry::lookup_breed(b.id).map(|x| x.id),
            Some(b.id)
        );
    }
    for a in ALGORITHMS {
        assert_eq!(
            wasm4pm_facts_registry::lookup_algorithm(a.id).map(|x| x.id),
            Some(a.id)
        );
    }
    assert!(wasm4pm_facts_registry::lookup_breed("__not_a_real_breed__").is_none());
    assert!(wasm4pm_facts_registry::lookup_algorithm("__not_a_real_algorithm__").is_none());
}

/// `algorithms_by_category` partitions all 60 algorithms with no loss and
/// no double-counting -- a real aggregate query over the generated facts.
#[test]
fn algorithms_by_category_partitions_all_algorithms_exactly() {
    let mut categories: Vec<&str> = ALGORITHMS.iter().map(|a| a.category).collect();
    categories.sort_unstable();
    categories.dedup();
    let total: usize = categories
        .iter()
        .map(|c| wasm4pm_facts_registry::algorithms_by_category(c).len())
        .sum();
    assert_eq!(total, ALGORITHMS.len(), "category partition must cover every algorithm exactly once");
}
